 29	/**
 30	 * `EditModal` is a React Functional Component that allows editing a Kubernetes resource property inside a modal.
 31	 *
 32	 * @component
 33	 * @param {object} props - The properties that define the behavior and display of the `EditModal`.
 34	 * @param {K8sResourceCommon} props.resource - The Kubernetes resource that will be modified.
 35	 * @param {K8sModel} props.model - The model for the Kubernetes resource.
 36	 * @param {string | string[]} props.jsonPath - The JSON path to the property in the resource that will be modified.
 37	 * @param {string} props.title - The title of the modal.
 38	 * @param {string} props.label - The label of the field being edited.
 39	 * @param {ReactNode} [props.body] - The body content of the modal.
 40	 * @param {ReactNode} [props.headerContent] - The help popup header content of the input field.
 41	 * @param {ReactNode} [props.bodyContent] - The help popup content in the body of the input field.
 42	 * @param {'small' | 'default' | 'medium' | 'large'} [props.variant] - The size of the modal.
 43	 * @param {OnConfirmHookType} [props.onConfirmHook] - A hook that gets called when the user confirms the edit.
 44	 * @param {ModalInputComponentType} [props.InputComponent] - The component used for the input field.
 45	 * @param {string} [props.helperText] - Helper text that will be displayed under the input field.
 46	 * @param {string} [props.redirectTo] - The path to redirect to after the modal is closed.
 47	 * @param {ValidationHookType} [props.validationHook] - A hook that is used to validate the new value.
 48	 *
 49	 * @returns {ReactElement} Returns a `Modal` React Element that renders the modal.
 50	 */
 51	export const EditModal: FC<EditModalProps> = ({
 52	  body,
 53	  bodyContent,
 54	  headerContent,
 55	  helperText,
 56	  InputComponent,
 57	  isVisible = true,
 58	  jsonPath,
 59	  label,
 60	  model,
 61	  onConfirmHook = defaultOnConfirm,
 62	  redirectTo,
 63	  resource,
 64	  title,
 65	  validationHook,
 66	  variant,
 67	}) => {
 68	  const { t } = useForkliftTranslation();
 69	  const { toggleModal } = useModal();
 70	
 71	  const [isLoading, toggleIsLoading] = useToggle();
 72	  const navigate = useNavigate();
 73	  const [alertMessage, setAlertMessage] = useState<ReactNode>(null);
 74	  const [value, setValue] = useState(getValueByJsonPath(resource, jsonPath) as string);
 75	  const [validation, setValidation] = useState<ValidationMsg>({
 76	    msg: '',
 77	    type: ValidationState.Default,
 78	  });
 79	
 80	  const { namespace } = resource?.metadata ?? {};
 81	  const owner = resource?.metadata?.ownerReferences?.[0];
 82	
 83	  /*
 84	   * Init validation
 85	   */
 86	  useEffect(() => {
 87	    if (validationHook) {
 88	      const validationResult = validationHook(value);
 89	      setValidation(validationResult);
 90	    }
 91	  }, [validationHook, value]);
 92	
 93	  /**
 94	   * Handles value change.
 95	   */
 96	  const handleValueChange = (newValue: string) => {
 97	    setValue(newValue);
 98	
 99	    if (validationHook) {
100	      const validationResult = validationHook(newValue);
101	      setValidation(validationResult);
102	    }
103	  };
104	
105	  /**
106	   * Handles save action.
107	   */
108	  const handleSave = useCallback(async () => {
109	    toggleIsLoading();
110	
111	    try {
112	      await onConfirmHook({ jsonPath, model, newValue: value, resource });
113	
114	      if (redirectTo) {
115	        navigate(redirectTo);
116	      }
117	
118	      toggleModal();
119	    } catch (err) {
120	      toggleIsLoading();
121	
122	      if (err instanceof Error) {
123	        setAlertMessage(
124	          <AlertMessageForModals title={t('Error')} message={err.message ?? err.toString()} />,
125	        );
126	      } else {
127	        setAlertMessage(<AlertMessageForModals title={t('Error')} message={t('Unknown error')} />);
128	      }
129	    }
130	  }, [
131	    resource,
132	    value,
133	    onConfirmHook,
134	    jsonPath,
135	    model,
136	    navigate,
137	    redirectTo,
138	    t,
139	    toggleIsLoading,
140	    toggleModal,
141	  ]);
142	
143	  const onClick: (event: MouseEvent<HTMLButtonElement>) => void = (event) => {
144	    event.preventDefault();
145	  };
146	
147	  /**
148	   * InputComponent_ is a higher-order component that renders either the passed-in InputComponent, or a default TextInput,
149	   */
150	  const Component = InputComponent ? (
151	    <InputComponent
152	      value={value}
153	      onChange={(newValue) => {
154	        handleValueChange(String(newValue));
155	      }}
156	    />
157	  ) : (
158	    <TextInput
159	      spellCheck="false"
160	      id="modal-with-form-form-field"
161	      name="modal-with-form-form-field"
162	      value={value}
163	      onChange={(_e, newValue) => {
164	        handleValueChange(newValue);
165	      }}
166	      validated={validation.type}
167	    />
168	  );
169	
170	  const actions = [
171	    <Button
172	      key="confirm"
173	      variant={ButtonVariant.primary}
174	      onClick={handleSave}
175	      isDisabled={validation.type === ValidationState.Error}
176	      isLoading={isLoading}
177	    >
178	      {t('Save')}
179	    </Button>,
180	    <Button key="cancel" variant={ButtonVariant.secondary} onClick={toggleModal} autoFocus>
181	      {t('Cancel')}
182	    </Button>,
183	  ];
184	
185	  return (
186	    <Modal
187	      title={title}
188	      position="top"
189	      showClose={false}
190	      variant={variant ?? ModalVariant.small}
191	      isOpen={true}
192	      onClose={toggleModal}
193	      actions={actions}
194	    >
195	      <Stack hasGutter>
196	        <div>{body}</div>
197	
198	        {isVisible && (
199	          <Form id="modal-with-form-form">
200	            <FormGroupWithHelpText
201	              label={label}
202	              labelIcon={
203	                bodyContent || headerContent ? (
204	                  <HelpIconPopover header={headerContent} onClick={onClick}>
205	                    {bodyContent}
206	                  </HelpIconPopover>
207	                ) : undefined
208	              }
209	              fieldId="modal-with-form-form-field"
210	              helperText={validation.msg ?? helperText}
211	              helperTextInvalid={validation.msg ?? helperText}
212	              validated={validation.type}
213	            >
214	              {Component}
215	            </FormGroupWithHelpText>
216	          </Form>
217	        )}
218	      </Stack>
219	      {typeof owner === 'object' && <ItemIsOwnedAlert owner={owner} namespace={namespace} />}
220	      {alertMessage}
221	    </Modal>
222	  );
223	};

